// ═══════════════════════════════════════════════════════════
// Process each locale file
// ═══════════════════════════════════════════════════════════
const langCodes = ['ko','en','ja','zh','zh-TW','es','fr','de','pt','ru','ar','vi','th','id','hi'];

let successCount = 0;
let errorCount = 0;

for (const code of langCodes) {
  const fileName = code + '.js';
  const filePath = path.join(LOCALES_DIR, fileName);
  
  if (!fs.existsSync(filePath)) {
    console.log(`⚠️ SKIP: ${fileName} not found`);
    errorCount++;
    continue;
  }

  try {
    let content = fs.readFileSync(filePath, 'utf-8');
    
    const jsonMatch = content.match(/export\s+default\s+(\{[\s\S]*\})\s*;?\s*$/);
    if (!jsonMatch) {
      console.log(`⚠️ SKIP: ${fileName} - cannot parse`);
      errorCount++;
      continue;
    }

    let obj;
    try {
      obj = JSON.parse(jsonMatch[1]);
    } catch (e) {
      obj = (new Function('return ' + jsonMatch[1]))();
    }

    // Inject campMgr guide keys
    const cCode = code;
    const cmGuideKeys = campGuide[cCode] || campGuide['en'];
    if (!obj.campMgr) obj.campMgr = {};
    Object.assign(obj.campMgr, cmGuideKeys);

    // Inject jb guide keys
    const jbGuideKeys = jbGuide[cCode] || jbGuide['en'];
    if (!obj.jb) obj.jb = {};
    Object.assign(obj.jb, jbGuideKeys);

    // Write back
    const newContent = 'export default ' + JSON.stringify(obj) + ';\n';
    fs.writeFileSync(filePath, newContent, 'utf-8');
    
    const cmCount = Object.keys(cmGuideKeys).length;
    const jbCount = Object.keys(jbGuideKeys).length;
    console.log(`✅ ${fileName}: +${cmCount} campMgr guide keys, +${jbCount} jb guide keys`);
    successCount++;
  } catch (e) {
    console.log(`❌ ERROR: ${fileName} - ${e.message}`);
    errorCount++;
  }
}

console.log(`\n═══ Done: ${successCount} success, ${errorCount} errors ═══`);
